const express = require('express');
const { Client } = require('@elastic/elasticsearch');

const app = express();
app.use(express.json());

const esClient = new Client({
  node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200'
});

// Health check endpoint
app.get('/health', async (req, res) => {
  try {
    const health = await esClient.cluster.health();
    res.json({ status: 'ok', elasticsearch: health });
  } catch (error) {
    res.status(503).json({ status: 'error', message: error.message });
  }
});

// List all indices
app.get('/indices', async (req, res) => {
  try {
    const result = await esClient.cat.indices({ format: 'json' });
    res.json(result);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Get index mapping
app.get('/indices/:index/mapping', async (req, res) => {
  try {
    const { index } = req.params;

    if (!isValidIndexName(index)) {
      return res.status(400).json({ error: 'Invalid index name' });
    }

    const result = await esClient.indices.getMapping({ index });
    res.json(result);
  } catch (error) {
    res.status(error.meta?.statusCode || 500).json({ error: error.message });
  }
});

// Search an index with query DSL
app.post('/search/:index', async (req, res) => {
  try {
    const { index } = req.params;
    const { query, from, size, sort, aggs, _source, highlight } = req.body;

    if (!isValidIndexName(index)) {
      return res.status(400).json({ error: 'Invalid index name' });
    }

    // Build the search body
    const searchBody = {};

    if (query) {
      searchBody.query = query;
    }

    if (sort) {
      searchBody.sort = sort;
    }

    if (aggs) {
      searchBody.aggs = aggs;
    }

    if (_source !== undefined) {
      searchBody._source = _source;
    }

    if (highlight) {
      searchBody.highlight = highlight;
    }

    const searchParams = {
      index,
      body: searchBody,
      from: from || 0,
      size: size !== undefined ? Math.min(size, 10000) : 10
    };

    const result = await esClient.search(searchParams);

    res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      aggregations: result.aggregations || null,
      took: result.took,
      timed_out: result.timed_out
    });
  } catch (error) {
    res.status(error.meta?.statusCode || 500).json({ error: error.message });
  }
});

// Multi-search across multiple indices
app.post('/msearch', async (req, res) => {
  try {
    const { searches } = req.body;

    if (!Array.isArray(searches) || searches.length === 0) {
      return res.status(400).json({ error: 'searches must be a non-empty array' });
    }

    const body = [];
    for (const search of searches) {
      if (!search.index || !isValidIndexName(search.index)) {
        return res.status(400).json({ error: `Invalid index name: ${search.index}` });
      }

      body.push({ index: search.index });
      body.push({
        query: search.query || { match_all: {} },
        size: search.size !== undefined ? Math.min(search.size, 10000) : 10,
        from: search.from || 0
      });
    }

    const result = await esClient.msearch({ body });

    res.json({
      responses: result.responses.map(r => ({
        total: r.hits?.total,
        hits: r.hits?.hits,
        aggregations: r.aggregations || null,
        took: r.took,
        timed_out: r.timed_out,
        error: r.error || null
      }))
    });
  } catch (error) {
    res.status(error.meta?.statusCode || 500).json({ error: error.message });
  }
});

