    if (!isValidIndexName(index)) {
      return res.status(400).json({ error: 'Invalid index name' });
    }

    const countParams = { index };
    if (query) {
      countParams.body = { query };
    }

    const result = await esClient.count(countParams);
    res.json({ count: result.count });
