// Validate index name to prevent injection or access to dangerous internal indices
function isValidIndexName(index) {
  if (!index || typeof index !== 'string') {
    return false;
  }

  // Disallow empty or whitespace-only names
  if (index.trim().length === 0) {
    return false;
  }

  // Block patterns that could be dangerous
  // Disallow wildcards and broad patterns that could match everything
  if (index === '*' || index === '_all') {
    return false;
  }

  // Disallow names starting with underscore (internal Elasticsearch indices)
  if (index.startsWith('_')) {
    return false;
  }

  // Basic character validation: allow alphanumeric, hyphens, underscores, dots, and wildcards within names
  const validPattern = /^[a-zA-Z0-9\-_.*]+$/;
  if (!validPattern.test(index)) {
    return false;
  }

  // Disallow path traversal attempts
  if (index.includes('..')) {
    return false;
  }

  return true;
}

